var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"오보에입니다.","JPN":"オーボエです。","ENG":"It is an oboe.","TWN":"是雙簧管。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L3_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"엘리시움 계통의 침식체들에게는 힘의 원천이자, 동시에 아티팩트이기도 한 물건이죠.","JPN":"エリシウム系の侵食体には力の源であり、アーティファクトでもあるものです。","ENG":"To the C.O.s of Elysium, it is the source of their power, but it is also an Artifact.","TWN":"對於愛樂組織的侵蝕體來說，既是力量的源泉，也是人造神器。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"그 효과는 공명을 통한 차원계면 손상, 정신 장악 혹은…….","JPN":"その効果は共鳴による次元界面の損傷、精神掌握または……","ENG":"Its effects include damaging the dimension surface through resonance, controlling the mind, and–","TWN":"它的效果是透過共鳴造成次元裂縫損傷，掌握精神或……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"호오, 역시 모리어티 교수님은 척척박사시네요.","JPN":"ほお、やっぱりモリアーティ教授はなんでも知ってますね。","ENG":"Ho-oh. I knew you were so smart, Professor Moriarty.","TWN":"喔，莫里蒂教授果然是行動百科呀。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"이걸 이용하면, 저희 교단에도 음악가를 둘 수 있을지도 모르겠네요.","JPN":"利用すれば、我々の教団にも音楽家を設けることができるかもしれません。","ENG":"Maybe we can use this to place a musician in our order as well.","TWN":"有了這個，說不定我們教團也能有個音樂家了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"헤헷, 성찬식을 열 때마다 연주를 들려달라고 하면 재밌겠다!","JPN":"えへっ、聖餐式のたびに演奏を聞かせてもらいたい！","ENG":"Hehe, it would be fun to ask for a performance every time we have a feast!","TWN":"嘿嘿，如果每次的盛宴儀式上都能聽到演奏，應該很有意思吧！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"또 다른 건 없나요?","JPN":"他はありませんか？","ENG":"Anything else?","TWN":"還有別的嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"고고학부장의 신분 말고도, 교수님은 사회적으로 성공하신 분이셨잖아요.","JPN":"教授は考古学部長であるだけじゃなく、社会的に成功した方だったじゃないですか。","ENG":"You were the Dean of Archeology, but you were also socially successful.","TWN":"教授除了考古學教授的這個身分，在社會上也是個頗有成就的人吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"성황청의 고위 사제 몇몇과 관리국 고위직과 커넥션이 닿아 있습니다.","JPN":"聖皇庁の高位司祭何人かと、管理局の上層部とコネクションがあります。","ENG":"I have some connections with a few high-ranking priests in the Holy Curia and the high-ranking employees of the Administration.","TWN":"聖皇廳的幾個高階祭司和管理局高層有聯繫。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"제 이름과 모습을 대면, 어떤 일이든 흔쾌히 협조할 겁니다.","JPN":"私の姿で名乗ればどんなことでも快く協力してくれるはずです。","ENG":"They will gladly offer assistance if you give them my name and appearance.","TWN":"只要說出我的名字和模樣，任何事情他們都會欣然配合。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"성황청이랑 관리국이라…….","JPN":"聖皇庁と管理局かあ……","ENG":"Holy Curia and the Administration...","TWN":"聖皇廳和管理局……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"나쁘진 않지만, 그렇다고 확 끌리는 느낌은 아니네요.","JPN":"悪くはないですけど、なんだかピンと来ませんね。","ENG":"It's not bad, but it's not that enticing either.","TWN":"雖然不錯，但還不是很吸引人。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"역시 이런 규모로 레지나가 이끄는 학회를 따라잡는 건 어렵겠어요.","JPN":"やっぱりこんな規模でレジーナの率いる学会に追いつくのは難しい気がします。","ENG":"It would be difficult to keep up with Regina's Society with a size this small.","TWN":"果然以這種規模，是很難追上蕾佳娜帶領的學會。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우웅, 당분간은 소수파답게 게릴라로 가야 할까?","JPN":"うーん、しばらくは少数派らしくゲリラ戦法で行きましょうか。","ENG":"Mmh, maybe we should stick to guerilla warfare since we're short on people.","TWN":"現在暫時是少數派，要不要打打遊擊？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"이번 일에 학회 측 인사인 리벳이 휘말리게 되어, 저희의 존재가 노출되었을 겁니다.","JPN":"今回の事件に学会側の人物であるリベットが巻き込まれて、私たちの存在も知られているはずです。","ENG":"Since Rivet, one of the Society's important members, was involved, we can safely assume that they know of our existence.","TWN":"學會成員里維被捲入此次事件，我們的存在肯定被暴露了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"곧 학회 측의 견제를 받게 되겠죠.","JPN":"すぐ、学会側がけん制してくるでしょう。","ENG":"The Society will soon interfere.","TWN":"很快就會受到學會的牽制。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"예상컨대, 주축은 대대로 학회에서 처형을 담당했던 법학부.","JPN":"その要となるのはおそらく、学会で代々処刑を担当してきた法学部。","ENG":"I imagine the main forces will include the Law Department, which handles the execution in the Society,","TWN":"預計，核心壓力會來自世代在學會負責處決的法學院。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"그리고 그릇의 관리 문제로 책임을 피하기 어렵게 된 종교학부. 두 곳이 될 겁니다.","JPN":"そして器の管理問題で責任を問われるであろう宗教学部。この二つだと予想されます。","ENG":"and the Religion Department, which will take the brunt of the responsibility for failing to keep the vessel in check.","TWN":"以及因為器皿管理問題而難以逃避責任的宗教學院，這二個地方。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"대비를 해두는 편이 좋을 것 같습니다.","JPN":"対策を練ったほうが良いかと。","ENG":"We should make some preparations.","TWN":"最好是對此做好準備。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"뭐, 알겠어요. 고마워요. 모리어티 교수님.","JPN":"まあ、わかりました。ありがとう、モリアーティ教授。","ENG":"Hmm, okay. Thank you, Professor Moriarty.","TWN":"嗯，知道了。謝謝你，莫里蒂教授。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"필요할 때 부를 테니, 제 안에서 다시 하나가 되어주시겠어요?","JPN":"必要になったらまた呼びますので、私の中でまた一つになってもらえますか？","ENG":"I'll call you when I need you, so would you return inside and become one again?","TWN":"必要時我會叫你，能在我體內再次合而為一嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하아, 역시 모두가 행복할 낙원을 만드는 일은 쉬운 일이 아니네요.","JPN":"はあ、やっぱり皆が幸せに暮らせる楽園を作るのって、難しいことですね。","ENG":"*Sigh.* It's not easy to create a paradise where everyone can be happy.","TWN":"哈啊，果然打造所有人都幸福的樂園不是件容易的事情。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"이것저것 생각해야 할 게 너무~ 많아요.","JPN":"考えないといけないことが多すぎます。","ENG":"There are soooo many things to think about.","TWN":"要考慮的事情真的太~多了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그냥 모든 사람들이 자존심을 내려놓고, 호수의 이름 아래 하나가 되면 좋을 텐데.","JPN":"みんなプライドを捨てて、湖の名のもとに一つになっちゃえばいいのに。","ENG":"Why can't everyone just throw away their pride and become one under the name of the Lake?","TWN":"要是所有人都放下自尊，在湖水的名義下合而為一就好了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그렇지 않나요, 나의 기사님?","JPN":"そう思いませんか？　騎士様。","ENG":"Wouldn't you agree, my knight?","TWN":"對不對，我的騎士？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"걱정 마십시오. 나의 어머니시여.","JPN":"心配入りません、お母さん。","ENG":"Do not worry, Mother.","TWN":"不必擔心，我的母親。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"호수가 하나가 될 날이…… 그리 머지 않았을 테니까요.","JPN":"湖が一つになる日は……そう遠くありませんので。","ENG":"It will not be long... until we become one with the Lake.","TWN":"湖水合而為一的那天……很快就會到來了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이번 일로 인해, 기관은 괴멸적인 피해를 입었을 겁니다.","JPN":"今回のことで、機関は壊滅寸前の被害を受けています。","ENG":"The Institution must be severely damaged after this incident.","TWN":"因為此次事件，機關受到了毀滅性的損失。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"복수심에 찬 사냥개들이 이를 갈겠지만, 그들에겐 상처를 회복할 시간이 필요하겠죠.","JPN":"猟犬たちは復讐心に燃えているでしょうが……傷を癒す時間が必要でしょう。","ENG":"The hounds will be yearning for revenge, but they will need time to lick their wounds.","TWN":"滿是復仇之心的獵犬肯定在咬牙切齒呢，但他們需要時間來恢復傷口。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"결국, 로이 버넷을 맛보지 못한 게 아쉽네요.","JPN":"結局、ロイ・バーネットを味わえなかったのが心残りです。","ENG":"It's a shame I didn't get to taste Roy Burnett.","TWN":"唔，最終，還是沒能嘗到羅伊，真是可惜。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"분에 겨운 감정을 꾹꾹 눌러 참고 있던 기관장의 표정도 꽤 볼만 했어요.","JPN":"悔しさを抑え込んでいた機関長の顔もなかなかの見ものでした。","ENG":"It was entertaining to see the face of the Chief holding in her fury.","TWN":"機關長強忍住憤怒的表情也值得一看。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"나중에는 다들 어떤 맛을 보여줄지…… 이브는 다가올 그 날이 너무 기대되는 걸요.","JPN":"つぎはみんなどんな味を出してくれるか……イヴはその日が待ち遠しいです。","ENG":"What will they all taste like...? Eve is so excited for that day to come.","TWN":"以後大家會展示什麼樣的味道呢……伊芙非常期待即將到來的那一天。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그것도 좋지만, 지금은 다른 쪽을 더 우선시하는 것이 좋겠습니다.","JPN":"それも良いですが、今は他のことを優先した方が良いかと思います。","ENG":"That is great, but I suggest you prioritise something else for now.","TWN":"那固然好，但現在最好是優先考慮另一方面。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"다른 쪽이라고 하시면?","JPN":"他のこと、と言いますと？","ENG":"Something else?","TWN":"另一方面？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"물론, 뿔뿔이 흩어진 지식의 호수의 파편을 모으는 일입니다.","JPN":"もちろん、ばらばらに散った知識の湖の破片を集めることです。","ENG":"The task of gathering the scattered Fragments of the Lake of Knowledge.","TWN":"當然就是，收集到處分散的知識湖水碎片。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"마왕의 위계를 두고 에델 마이트너와 겨루실 생각이라면…….","JPN":"魔王の位階をめぐって、エデル・マイトナーと競うつもりでいらっしゃるなら……","ENG":"If you are to challenge Edel Meitner for the role of Demon Lord...","TWN":"若想就魔王位階與艾瑟兒較量……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"조금이라도 많은 파편을 확보해두는 편이 어머니께 유리할 테니까요.","JPN":"破片を少しでも多く確保しておいた方が、お母さんにも有利になるはずですので。","ENG":"It will be to your advantage to secure as many Fragments as possible.","TWN":"那麼多收集一點碎片，對母親更有利。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"후후, 알고 있답니다.","JPN":"ふふ、わかっています。","ENG":"Fu fuu, I'm aware.","TWN":"呵呵，我也知道。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 어머니에게 레지나가 있듯, 저에게는 당신이 있는 걸요.","JPN":"ですがお母さんにレジーナがいるのと同じように、私にはあなたがいますもの。","ENG":"But just like how Mother has Regina, I have you.","TWN":"不過，就像母親有蕾佳娜一樣，我有你。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우리 가아그셰블라와 대적했던 바로 당신이.","JPN":"我々ガアグシェブラに立ち向かったあなたが。","ENG":"You, who fought against us Gha'agsheblah.","TWN":"和加格舍夫拉對抗過的你。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"후후. 과찬이시군요.","JPN":"ふふ、身に余るお言葉です。","ENG":"Hah hah, I'm honoured.","TWN":"呵呵，過獎了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 그저 지나가버린 꿈 같은 과거일 뿐.","JPN":"ですがそれは過ぎ去った夢のような過去に過ぎません。","ENG":"But it is merely a past that feels like a dream.","TWN":"但那只是如夢般的過去。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지금은 지식의 호수를 섬기는…… 당신의 기사일 뿐입니다.","JPN":"今の私は知識の湖に仕える……あなたの騎士です。","ENG":"Now, I serve the Lake of Knowledge... I am your knight.","TWN":"現在我只是侍奉知識湖水的……母親的騎士而已。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 힘에 적응하실 때까지 부디 이곳, 클리파 차원의 침소에서 쉬고 계십시오.","JPN":"その力に慣れるまで、このクリファ次元の寝床で休んでください。","ENG":"I urge you to rest here, in the Qlipha Dimension's shelter, until you adapt to your powers.","TWN":"在適應這股力量之前，請務必在逆卡巴拉次元休息。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니를 위한 교단은, 당분간 제가 이끌도록 하겠습니다.","JPN":"お母さんのための教団は、しばらく私が率いることにします。","ENG":"I will lead your order for the time being.","TWN":"為了母親，教團暫時由我來領導。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"모든 것은, 지식의 호수가 하나 되기 위해서.","JPN":"すべては、知識の湖が一つになるため。","ENG":"Everything... is for the Lake of Knowledge to become one.","TWN":"一切都是為了讓知識湖水合而為一。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하암~ 그래요.","JPN":"ふああ……わかりました。","ENG":"*Yawn.* Okay.","TWN":"哈啊～好吧。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"아무래도 전 좀 자야겠어요. ","JPN":"少し眠らないと。 ","ENG":"I'll get some sleep.","TWN":"我需要睡一會兒。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"그럼, 부탁할게요. 나의 기사님.","JPN":"じゃあ、お願いしますね。私の騎士様。","ENG":"I'll leave it to you, my knight.","TWN":"那麼，就拜託你了，我的騎士。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};